<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Falling Sand</title>
  <style>
    body {
      background-color: #1e1e1e;
      color: white;
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      height: 100vh;
      margin: 0;
    }
    #controls {
      display: flex;
      gap: 10px;
      margin-bottom: 10px;
    }
    button {
      padding: 8px 16px;
      border-radius: 5px;
      border: none;
      background-color: #333;
      color: white;
      cursor: pointer;
    }
    button:hover {
      background-color: #444;
    }
    canvas {
      border: 2px solid #444;
      background-color: #1e1e1e;
    }
  </style>
</head>
<body>
  <div id="controls">
    <button id="mat-sand">Sand</button>
    <button id="mat-water">Water</button>
    <button id="mat-wall">Wall</button>
    <button id="mat-acid">Acid</button>
    <button id="mat-empty">Erase</button>
    <button id="clear">Clear</button>
  </div>
  <canvas id="sand" width="400" height="400"></canvas>

  <script>
    const w = 80;
    const h = 80;
    const cellWidth = 5;
    const cellHeight = 5;

    let grid = [];

    function initGrid() {
      for (let x = 0; x < w; x++) {
        grid[x] = [];
        for (let y = 0; y < h; y++) {
          grid[x][y] = "empty";
        }
      }
    }

    function render() {
      const ctx = document.getElementById("sand").getContext("2d");
      ctx.fillStyle = "#1e1e1e";
      ctx.fillRect(0, 0, w * cellWidth, h * cellHeight);
      for (let x = 0; x < w; x++) {
        for (let y = 0; y < h; y++) {
          const mat = grid[x][y];
          let color;
          if (mat === "sand") color = "#f9d657";
          else if (mat === "water") color = "#4ecdc4";
          else if (mat === "wall") color = "#808080";
          else if (mat === "acid") color = "#ff6b6b";
          else continue;
          ctx.fillStyle = color;
          ctx.fillRect(x * cellWidth, y * cellHeight, cellWidth, cellHeight);
        }
      }
    }

    function simulateStep() {
      for (let y = h - 1; y >= 0; y--) {
        for (let x = 0; x < w; x++) {
          const mat = grid[x][y];
          if (mat === "empty" || mat === "wall") continue;
          processMovement(x, y);
        }
      }

      const acidPositions = [];
      for (let x = 0; x < w; x++) {
        for (let y = 0; y < h; y++) {
          if (grid[x][y] === "acid") {
            acidPositions.push([x, y]);
          }
        }
      }

      for (const [x, y] of acidPositions) {
        const belowY = y + 1;
        if (belowY < h) {
          const matBelow = grid[x][belowY];
          if (matBelow === "sand" || matBelow === "wall") {
            grid[x][belowY] = "empty";
          }
        }

        const xLeft = x - 1;
        if (xLeft >= 0) {
          const matLeft = grid[xLeft][y];
          if (matLeft === "sand" || matLeft === "wall") {
            grid[xLeft][y] = "empty";
          }
        }

        const xRight = x + 1;
        if (xRight < w) {
          const matRight = grid[xRight][y];
          if (matRight === "sand" || matRight === "wall") {
            grid[xRight][y] = "empty";
          }
        }
      }
    }

    function processMovement(x, y) {
      const mat = grid[x][y];
      switch (mat) {
        case "sand":
          processSand(x, y);
          break;
        case "water":
          processWater(x, y);
          break;
        case "acid":
          processAcid(x, y);
          break;
      }
    }

    function processSand(x, y) {
      const belowY = y + 1;
      if (belowY >= h) return;
      const belowMat = grid[x][belowY];
      if (belowMat === "empty") {
        swapCells(x, y, x, belowY);
        return;
      } else if (["water", "acid"].includes(belowMat)) {
        swapCells(x, y, x, belowY);
        return;
      }
      const dir = ((x + y) % 2) ? -1 : 1;
      for (let d of [dir, -dir]) {
        let nx = x + d;
        if (nx < 0 || nx >= w) continue;
        const belowDiagMat = grid[nx][belowY];
        if (["empty", "water", "acid"].includes(belowDiagMat)) {
          swapCells(x, y, nx, belowY);
          return;
        }
      }
    }

    function processWater(x, y) {
      const belowY = y + 1;
      if (belowY >= h) return;
      const belowMat = grid[x][belowY];
      if (["empty", "water", "acid"].includes(belowMat)) {
        swapCells(x, y, x, belowY);
        return;
      }
      const dir = (x % 2) ? -1 : 1;
      for (let d of [dir, -dir]) {
        let nx = x + d;
        if (nx < 0 || nx >= w) continue;
        const adjMat = grid[nx][y];
        if (adjMat === "empty") {
          swapCells(x, y, nx, y);
          return;
        }
      }
    }

    function processAcid(x, y) {
      const belowY = y + 1;
      if (belowY >= h) return;
      const belowMat = grid[x][belowY];
      if (["empty", "water", "acid"].includes(belowMat)) {
        swapCells(x, y, x, belowY);
        return;
      }
      const dir = (x % 2) ? -1 : 1;
      for (let d of [dir, -dir]) {
        let nx = x + d;
        if (nx < 0 || nx >= w) continue;
        const adjMat = grid[nx][y];
        if (adjMat === "empty") {
          swapCells(x, y, nx, y);
          return;
        }
      }
    }

    function swapCells(x1, y1, x2, y2) {
      const temp = grid[x1][y1];
      grid[x1][y1] = grid[x2][y2];
      grid[x2][y2] = temp;
    }

    initGrid();
    render();

    let currentMaterial = "sand";
    let isMouseDown = false;

    document.getElementById("mat-sand").addEventListener("click", () => {
      currentMaterial = "sand";
    });
    document.getElementById("mat-water").addEventListener("click", () => {
      currentMaterial = "water";
    });
    document.getElementById("mat-wall").addEventListener("click", () => {
      currentMaterial = "wall";
    });
    document.getElementById("mat-acid").addEventListener("click", () => {
      currentMaterial = "acid";
    });
    document.getElementById("mat-empty").addEventListener("click", () => {
      currentMaterial = "empty";
    });

    document.getElementById("clear").addEventListener("click", () => {
      window.sim.clear();
      render();
    });

    const canvas = document.getElementById("sand");
    canvas.addEventListener("mousedown", (e) => {
      isMouseDown = true;
      updateCell(e);
    });
    canvas.addEventListener("mouseup", () => {
      isMouseDown = false;
    });
    canvas.addEventListener("mouseleave", () => {
      isMouseDown = false;
    });
    canvas.addEventListener("mousemove", (e) => {
      if (isMouseDown) updateCell(e);
    });

    function updateCell(e) {
      const rect = canvas.getBoundingClientRect();
      const mouseX = e.clientX - rect.left;
      const mouseY = e.clientY - rect.top;
      const x = Math.floor(mouseX / cellWidth);
      const y = Math.floor(mouseY / cellHeight);
      if (x >= 0 && x < w && y >= 0 && y < h) {
        window.sim.set(x, y, currentMaterial);
        render();
      }
    }

    function animate() {
      window.sim.tick(1);
      requestAnimationFrame(animate);
    }
    requestAnimationFrame(animate);

    window.sim = {
      w: w,
      h: h,
      tick(n) {
        for (let i = 0; i < n; i++) simulateStep();
      },
      get(x, y) {
        if (x >= 0 && x < w && y >= 0 && y < h) return grid[x][y];
        else return "empty";
      },
      set(x, y, material) {
        if (x >= 0 && x < w && y >= 0 && y < h) grid[x][y] = material;
      },
      clear() {
        for (let x = 0; x < w; x++) {
          for (let y = 0; y < h; y++) {
            grid[x][y] = "empty";
          }
        }
      },
    };
  </script>
</body>
</html>
